import clsx from 'clsx';
import {
  useMemo,
  useState,
  type PropsWithChildren,
  type ReactNode,
  Children,
} from 'react';
import { FormattedMessage } from 'react-intl';
import { isElement } from 'react-is';

import {
  ChevronDownSmallIcon,
  ChevronUpSmallIcon,
} from '@dynatrace/strato-icons';

import * as styles from './ShowMorePanel.sty.js';
import { Button } from '../../../../buttons/button/Button.js';
import { isDev } from '../../../../core/utils/is-node-environment.js';
import { Flex } from '../../../../layouts/flex/Flex.js';

/**
 * Compound component for the extendable content of the show more panel.
 */
const ExtendedContent = ({ children }: PropsWithChildren) => children;

/**
 * Compound component for the always visible content of the show more panel.
 */
const PrimaryContent = ({ children }: PropsWithChildren) => children;

function useChildrenSlots(children: ReactNode) {
  const memoizedSlots = useMemo(() => {
    const slots: {
      extendedContent?: ReactNode;
      primaryContent?: ReactNode;
    } = {};

    Children.forEach(children, (child) => {
      if (isElement(child)) {
        switch (child.type) {
          case ExtendedContent:
            slots.extendedContent = child;
            break;
          case PrimaryContent:
          default:
            slots.primaryContent = child;
            break;
        }
      }
    });
    return slots;
  }, [children]);

  return memoizedSlots;
}

/**
 * Panel with a show more/less control for the collapsing of segment presets.
 * @internal
 */
const ShowMorePanelRoot = ({ children }: PropsWithChildren) => {
  const { primaryContent, extendedContent } = useChildrenSlots(children);
  const [isExpanded, setIsExpanded] = useState(false);

  if (!children) {
    if (isDev()) {
      // eslint-disable-next-line no-console
      console.warn(
        'SegmentSelector: The used child is not supported by the ExpandableSection.',
      );
    }
    return null;
  }

  if (!extendedContent) {
    return primaryContent;
  }

  const icon = isExpanded ? <ChevronUpSmallIcon /> : <ChevronDownSmallIcon />;
  const dataDtProperties = `state:${isExpanded ? 'less' : 'more'}`;

  return (
    <>
      <ul className={styles.list}>{primaryContent}</ul>
      {isExpanded && (
        <ul
          className={clsx(styles.expandableWrapper, {
            [styles.expandableWrapperExpanded]: isExpanded,
            [styles.expandableWrapperCollapsed]: !isExpanded,
          })}
        >
          {extendedContent}
        </ul>
      )}
      <Button
        onClick={() => setIsExpanded((previousState) => !previousState)}
        width="full"
        textAlign="start"
        style={{
          transitionTimingFunction: 'none',
          transitionDuration: '0s',
          transition: 'none',
        }}
        data-dt-name="ShowMoreLess"
        data-dt-properties={dataDtProperties}
      >
        <Flex gap={2} as="span" paddingLeft={4}>
          <FormattedMessage
            defaultMessage="Show {isExpanded, select, true {less} false {more} other{}}"
            id="mYmd/xMZulbADHsY"
            description="Text shown on the expanding button within the SegmentSelector preset list, when currently expanded."
            values={{ isExpanded }}
          />
          {icon}
        </Flex>
      </Button>
    </>
  );
};

/**
 * Panel with a show more/less control for the collapsing of segment presets.
 * @internal
 */
export const ShowMorePanel = Object.assign(ShowMorePanelRoot, {
  PrimaryContent,
  ExtendedContent,
});
